// Keywords that signal breaking or high-impact changes
const KEYWORDS = [
  'breaking', 'deprecated', 'removed',
  'code node', 'task runner', 'python',
  'expression', 'webhook', '$env',
  'publish', 'migration'
];

// Get static data to track last checked version
const staticData = this.getWorkflowStaticData('global');
const lastChecked = staticData.lastCheckedVersion || '0.0.0';

// Parse semver string to comparable array [major, minor, patch]
function parseSemver(tag) {
  const clean = tag.replace(/^[vn@]+/, '');
  const parts = clean.split('.').map(Number);
  return [parts[0] || 0, parts[1] || 0, parts[2] || 0];
}

function isNewer(versionTag, baseline) {
  const a = parseSemver(versionTag);
  const b = parseSemver(baseline);
  for (let i = 0; i < 3; i++) {
    if (a[i] > b[i]) return true;
    if (a[i] < b[i]) return false;
  }
  return false;
}

const releases = $input.all();
let releaseList = [];
if (releases.length === 1 && Array.isArray(releases[0].json)) {
  releaseList = releases[0].json;
} else {
  releaseList = releases.map(r => r.json);
}

const matched = [];
let newestVersion = lastChecked;

for (const release of releaseList) {
  const tag = release.tag_name || '';
  const body = (release.body || '').toLowerCase();
  const name = (release.name || '').toLowerCase();
  const text = body + ' ' + name;

  if (!isNewer(tag, lastChecked)) continue;
  if (isNewer(tag, newestVersion)) newestVersion = tag;

  const hits = KEYWORDS.filter(kw => text.includes(kw.toLowerCase()));
  if (hits.length > 0) {
    matched.push({
      version: tag,
      name: release.name || tag,
      keywords: hits,
      url: release.html_url || `https://github.com/n8n-io/n8n/releases/tag/${tag}`,
      published: release.published_at || ''
    });
  }
}

staticData.lastCheckedVersion = newestVersion;
staticData.lastRunAt = new Date().toISOString();

return [{ json: { matchedCount: matched.length, releases: matched, lastChecked: lastChecked, newLastChecked: newestVersion } }];

const data = $input.first().json;
const releases = data.releases;

const facts = releases.map(r => ({
  type: 'FactSet',
  facts: [
    { title: 'Version', value: r.version },
    { title: 'Keywords', value: r.keywords.join(', ') },
    { title: 'Published', value: r.published ? new Date(r.published).toLocaleDateString() : 'N/A' }
  ]
}));

const actions = releases.map(r => ({
  type: 'Action.OpenUrl',
  title: `View ${r.version}`,
  url: r.url
}));

const card = {
  type: 'message',
  attachments: [{
    contentType: 'application/vnd.microsoft.card.adaptive',
    contentUrl: null,
    content: {
      '$schema': 'http://adaptivecards.io/schemas/adaptive-card.json',
      type: 'AdaptiveCard',
      version: '1.4',
      body: [
        {
          type: 'TextBlock',
          size: 'Medium',
          weight: 'Bolder',
          text: `n8n Breaking Changes Alert (${releases.length} release${releases.length > 1 ? 's' : ''})`
        },
        {
          type: 'TextBlock',
          text: `Checked versions from ${data.lastChecked} to ${data.newLastChecked}`,
          isSubtle: true,
          wrap: true
        },
        ...facts
      ],
      actions: actions
    }
  }]
};

return [{ json: { teamsPayload: card } }];
